const data = $input.first().json;
const pending = parseInt(data.pending_count || 0);
const recentTopics = data.recent_topics || [];
const target = 21;
const needed = Math.max(0, target - pending);

if (needed === 0) {
  return [{ json: {
    skip: true,
    message: `Queue has ${pending} posts. No generation needed.`,
    needed: 0,
    recentTopics: recentTopics.slice(0, 20)
  }}];
}

return [{ json: {
  skip: false,
  needed,
  pending,
  recentTopics: recentTopics.slice(0, 20),
  message: `Queue has ${pending} posts. Generating ${needed} new posts.`
}}];

const response = $input.first().json;
const content = response.content;
let text = '';

if (Array.isArray(content)) {
  text = content
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('');
} else if (typeof content === 'string') {
  text = content;
}

text = text.replace(/```json/g, '').replace(/```/g, '').trim();

let topics = [];
try {
  topics = JSON.parse(text);
} catch(e) {
  const match = text.match(/\[[\s\S]*\]/);
  if (match) {
    topics = JSON.parse(match[0]);
  }
}

if (!Array.isArray(topics) || topics.length === 0) {
  throw new Error('Claude returned no valid topics: ' + text);
}

return topics.map(t => ({ json: t }));

const items = $input.all();
return [{
  json: {
    generated: items.length,
    timestamp: new Date().toISOString(),
    message: `Content generator: inserted ${items.length} new posts into queue`
  }
}];

return [{
  json: {
    generated: 0,
    timestamp: new Date().toISOString(),
    message: $input.first().json.message
  }
}];
